db_schema:
CREATE TABLE IF NOT EXISTS places (id INTEGER PRIMARY KEY, name TEXT NOT NULL CHECK(length(name) BETWEEN 1 AND 80), category TEXT NOT NULL CHECK(category IN ('restaurant','cafe','accommodation','attraction')), address TEXT NULL CHECK(address IS NULL OR length(address) <= 200), rating REAL NULL CHECK(rating IS NULL OR (rating >= 1 AND rating <= 5)), memo TEXT NULL CHECK(memo IS NULL OR length(memo) <= 1000), created_at TEXT NOT NULL, updated_at TEXT NOT NULL);

CREATE TABLE IF NOT EXISTS menu_items (id INTEGER PRIMARY KEY, place_id INTEGER NOT NULL, name TEXT NOT NULL CHECK(length(name) BETWEEN 1 AND 80), price_krw INTEGER NOT NULL CHECK(price_krw >= 0 AND price_krw <= 10000000), created_at TEXT NOT NULL, updated_at TEXT NOT NULL, FOREIGN KEY(place_id) REFERENCES places(id) ON DELETE CASCADE);

CREATE TABLE IF NOT EXISTS photos (id INTEGER PRIMARY KEY, place_id INTEGER NOT NULL, file_path TEXT NOT NULL, caption TEXT NULL CHECK(caption IS NULL OR length(caption) <= 140), order_index INTEGER NOT NULL CHECK(order_index >= 1 AND order_index <= 10), created_at TEXT NOT NULL, FOREIGN KEY(place_id) REFERENCES places(id) ON DELETE CASCADE, UNIQUE(place_id, order_index));
